const moneyKeys = new Set(["basePurchasePrice", "baseSellingPrice", "productDiscountPercentage", "stockQuantity", "purchasePriceOverride", "sellingPriceOverride", "value", "totalUsageLimit", "perCustomerUsageLimit", "minimumOrderSubtotal", "customerPaidShippingFee", "actualShippingCost", "sortOrder", "discountPercentage", "validityDays", "amount", "freeShippingThreshold", "abandonedCheckoutDelayHours", "inactiveCustomerDelayDays"]);
const boolKeys = new Set(["isActive", "isFeatured", "isCustomerSpecific", "isEnabled", "sendWhatsAppMessage", "serviceConfigured", "abandonedCheckoutEnabled", "inactiveCustomerEnabled", "isFreeShippingEnabled"]);

function castForm<T extends Record<string, any>>(data: T) {
  const output: Record<string, any> = {};
  for (const [key, value] of Object.entries(data)) {
    if (value === "") output[key] = null;
    else if (moneyKeys.has(key)) output[key] = value === null || value === undefined ? null : Number(value);
    else if (boolKeys.has(key)) output[key] = value === true || value === "true";
    else output[key] = value;
  }
  return output;
}

function usePagedParams(defaultPageSize = 20) {
  const [searchParams, setSearchParams] = useSearchParams();
  const page = Number(searchParams.get("page") || 1);
  const pageSize = Number(searchParams.get("pageSize") || defaultPageSize);
  const setParam = (key: string, value: string | number | undefined) => {
    const next = new URLSearchParams(searchParams);
    if (value === undefined || value === "") next.delete(key); else next.set(key, String(value));
    if (key !== "page") next.set("page", "1");
    setSearchParams(next);
  };
  return { searchParams, page, pageSize, setParam, setPage: (p: number) => setParam("page", p) };
}

function useToastMutation<TData, TVars = void>(mutationFn: (vars: TVars) => Promise<TData>, invalidate: unknown[]) {
  const queryClient = useQueryClient();
  const [message, setMessage] = useState<string | null>(null);
  const mutation = useMutation({ mutationFn, onSuccess: async () => { setMessage("Saved successfully."); await queryClient.invalidateQueries({ queryKey: invalidate }); }, onError: (error) => setMessage(error instanceof Error ? error.message : "Save failed.") });
  return { mutation, message, setMessage };
}

function InlineMessage({ message, onClose }: { message: string | null; onClose: () => void }) {
  if (!message) return null;
  return <div className="empty" role="status"><span>{message}</span> <Button variant="ghost" onClick={onClose}>Dismiss</Button></div>;
}

