const productSchema = z.object({ nameAr: z.string().min(1), nameEn: z.string().min(1), categoryId: z.string().min(1), basePurchasePrice: z.coerce.number().min(0), baseSellingPrice: z.coerce.number().min(0), productDiscountPercentage: z.coerce.number().min(0).max(100).nullable().optional(), productDiscountStartAt: z.string().nullable().optional(), productDiscountEndAt: z.string().nullable().optional() }).passthrough().refine((d) => !d.productDiscountStartAt || !d.productDiscountEndAt || new Date(d.productDiscountStartAt) <= new Date(d.productDiscountEndAt), { message: "Discount start must be before end.", path: ["productDiscountEndAt"] });
export function ProductDetailPage({ mode }: { mode?: "new" }) {
  const { id } = useParams();
  const isNew = mode === "new" || id === undefined;
  const navigate = useNavigate();
  const product = useQuery({ queryKey: ["products", id], queryFn: () => productsApi.get(id!), enabled: !isNew });
  const categories = useQuery({ queryKey: ["categories"], queryFn: categoriesApi.list });
  const { register, handleSubmit, reset, formState: { errors } } = useForm<any>({ resolver: zodResolver(productSchema), defaultValues: { isActive: true, isFeatured: false, basePurchasePrice: 0, baseSellingPrice: 0, sortOrder: 0 } });
  useEffect(() => { if (product.data) reset(product.data); }, [product.data, reset]);
  const save = useToastMutation(async (data: any) => isNew ? productsApi.create(castForm(data)) : productsApi.update(id!, castForm(data)), ["products"]);
  if (product.isLoading) return <Skeleton lines={8} />;
  if (product.error) return <ErrorState error={product.error} />;
  return <><PageHeader title={isNew ? "New product" : product.data?.nameEn ?? "Product"} actions={<LinkButton to="/products">Back to products</LinkButton>} /><InlineMessage message={save.message} onClose={() => save.setMessage(null)} /><form className="grid grid-2" onSubmit={handleSubmit(async (data) => { const saved = await save.mutation.mutateAsync(data) as Product; if (isNew) navigate(`/products/${saved.id}`); })}><Card className="grid"><h2>Product details</h2><Field label="Arabic name" error={String(errors.nameAr?.message ?? "")}><Input {...register("nameAr")} /></Field><Field label="English name" error={String(errors.nameEn?.message ?? "")}><Input {...register("nameEn")} /></Field><Field label="Category" error={String(errors.categoryId?.message ?? "")}><Select {...register("categoryId")}><option value="">Select category</option>{categories.data?.map((c) => <option value={c.id} key={c.id}>{c.nameEn}</option>)}</Select></Field><Field label="Arabic description"><Textarea {...register("descriptionAr")} /></Field><Field label="English description"><Textarea {...register("descriptionEn")} /></Field><div className="grid grid-2"><Field label="Purchase cost"><CurrencyInput {...register("basePurchasePrice")} /></Field><Field label="Selling price"><CurrencyInput {...register("baseSellingPrice")} /></Field></div><Field label="Discount percentage"><PercentageInput {...register("productDiscountPercentage")} /></Field><div className="grid grid-2"><Field label="Discount start"><DateInput {...register("productDiscountStartAt")} /></Field><Field label="Discount end" error={String(errors.productDiscountEndAt?.message ?? "")}><DateInput {...register("productDiscountEndAt")} /></Field></div><Field label="Featured"><Select {...register("isFeatured")}><option value="false">No</option><option value="true">Yes</option></Select></Field><Field label="Active"><Select {...register("isActive")}><option value="true">Active</option><option value="false">Inactive</option></Select></Field><Button disabled={save.mutation.isPending} type="submit">Save product</Button></Card></form>{!isNew && product.data ? <div className="grid grid-2" style={{ marginTop: "1rem" }}><ProductImageManager product={product.data} /><VariantManager product={product.data} /></div> : null}</>;
}

function ProductImageManager({ product }: { product: Product }) {
  const queryClient = useQueryClient();
  const invalidate = () => queryClient.invalidateQueries({ queryKey: ["products", product.id] });
  const [altAr, setAltAr] = useState("");
  const [altEn, setAltEn] = useState("");
  const upload = useMutation({ mutationFn: async (file: File) => { const uploaded = await uploadsApi.image(file, "products", product.id); return productsApi.addImage(product.id, { ...uploaded, altAr: altAr || undefined, altEn: altEn || undefined, isPrimary: product.images.length === 0 }); }, onSuccess: async () => { setAltAr(""); setAltEn(""); await invalidate(); } });
  const ordered = [...product.images].sort((a, b) => a.sortOrder - b.sortOrder);
  const move = (index: number, dir: -1 | 1) => { const next = [...ordered]; const t = index + dir; if (t < 0 || t >= next.length) return; [next[index], next[t]] = [next[t]!, next[index]!]; productsApi.reorderImages(product.id, next.map((im, i) => ({ id: im.id, sortOrder: i }))).then(invalidate); };
  return <Card className="grid"><h2>Images</h2><div className="grid grid-3"><Field label="New image alt (Arabic)"><Input value={altAr} onChange={(e) => setAltAr(e.currentTarget.value)} /></Field><Field label="New image alt (English)"><Input value={altEn} onChange={(e) => setAltEn(e.currentTarget.value)} /></Field><Field label="Upload image" hint="Cloudinary credentials stay server-side. This only sends the file to apps/api."><Input type="file" accept="image/*" onChange={(e) => { const file = e.currentTarget.files?.[0]; if (file) upload.mutate(file); }} /></Field></div>{upload.isPending ? <p>Uploading…</p> : null}{upload.error ? <ErrorState error={upload.error} /> : null}{ordered.length === 0 ? <EmptyState title="No images yet" body="Upload at least one image; the first becomes the primary image." /> : <div className="grid grid-3">{ordered.map((image, index) => <ProductImageCard key={image.id} productId={product.id} image={image} index={index} count={ordered.length} onMove={move} onChanged={invalidate} />)}</div>}</Card>;
}

function ProductImageCard({ productId, image, index, count, onMove, onChanged }: { productId: string; image: Product["images"][number]; index: number; count: number; onMove: (index: number, dir: -1 | 1) => void; onChanged: () => void }) {
  const [altAr, setAltAr] = useState(image.altAr ?? "");
  const [altEn, setAltEn] = useState(image.altEn ?? "");
  const saveAlt = useMutation({ mutationFn: () => productsApi.updateImage(productId, image.id, { altAr: altAr || null, altEn: altEn || null }), onSuccess: onChanged });
  const setPrimary = useMutation({ mutationFn: () => productsApi.updateImage(productId, image.id, { isPrimary: true }), onSuccess: onChanged });
  const del = useMutation({ mutationFn: () => productsApi.removeImage(productId, image.id), onSuccess: onChanged });
  return <Card><img className="image-thumb" src={image.url} alt={image.altEn ?? "Product image"} /><p><StatusBadge value={image.isPrimary ? "Primary" : "Gallery"} /></p><Field label="Alt (Arabic)"><Input value={altAr} onChange={(e) => setAltAr(e.currentTarget.value)} /></Field><Field label="Alt (English)"><Input value={altEn} onChange={(e) => setAltEn(e.currentTarget.value)} /></Field><div className="toolbar"><Button variant="secondary" disabled={saveAlt.isPending} onClick={() => saveAlt.mutate()}>Save alt</Button>{!image.isPrimary ? <Button variant="secondary" disabled={setPrimary.isPending} onClick={() => setPrimary.mutate()}>Set primary</Button> : null}<Button variant="ghost" disabled={index <= 0} onClick={() => onMove(index, -1)} aria-label="Move up">↑</Button><Button variant="ghost" disabled={index >= count - 1} onClick={() => onMove(index, 1)} aria-label="Move down">↓</Button><ConfirmDialog title="Delete image" body="This removes the image reference from the product." destructive onConfirm={() => del.mutate()}>{(open) => <Button variant="danger" onClick={open}>Delete</Button>}</ConfirmDialog></div></Card>;
}

function VariantManager({ product }: { product: Product }) {
  const queryClient = useQueryClient();
  const [editing, setEditing] = useState<Variant | null>(null);
  const [selected, setSelected] = useState<string | null>(product.variants[0]?.id ?? null);
  const movements = useQuery({ queryKey: ["variant-movements", selected], queryFn: () => variantsApi.movements(selected!), enabled: !!selected });
  const { register, handleSubmit, reset } = useForm<any>({ defaultValues: { sku: "", stockQuantity: 0, isActive: true } });
  const save = useMutation({ mutationFn: (data: any) => editing ? variantsApi.update(editing.id, castForm(data)) : variantsApi.create(product.id, castForm(data)), onSuccess: async () => { reset({ sku: "", stockQuantity: 0, isActive: true }); setEditing(null); await queryClient.invalidateQueries({ queryKey: ["products", product.id] }); } });
  return <Card className="grid"><h2>Variants and inventory</h2><DataTable caption="Variants" rows={product.variants} columns={[{ key: "sku", header: "SKU", render: (v) => <button className="button button-ghost" onClick={() => setSelected(v.id)}>{v.sku}</button> }, { key: "stockQuantity", header: "Exact stock", numeric: true }, { key: "purchasePriceOverride", header: "Purchase override", render: (v) => v.purchasePriceOverride ? egp.format(v.purchasePriceOverride) : "-" }, { key: "sellingPriceOverride", header: "Selling override", render: (v) => v.sellingPriceOverride ? egp.format(v.sellingPriceOverride) : "-" }, { key: "isActive", header: "Active", render: (v) => <StatusBadge value={v.isActive} /> }, { key: "actions", header: "Actions", render: (v) => <Button variant="secondary" onClick={() => { setEditing(v); reset(v); }}>Edit</Button> }]} empty="No variants" /><form className="grid" onSubmit={handleSubmit((d) => save.mutate(d))}><h2>{editing ? "Edit variant" : "Add variant"}</h2><div className="grid grid-3"><Field label="SKU"><Input {...register("sku", { required: true })} /></Field><Field label="Arabic display name"><Input {...register("nameAr")} /></Field><Field label="English display name"><Input {...register("nameEn")} /></Field><Field label="Size"><Input {...register("size")} /></Field><Field label="Arabic color"><Input {...register("colorAr")} /></Field><Field label="English color"><Input {...register("colorEn")} /></Field><Field label="Arabic material"><Input {...register("materialAr")} /></Field><Field label="English material"><Input {...register("materialEn")} /></Field><Field label="Stock quantity"><NumberInput {...register("stockQuantity")} /></Field><Field label="Purchase override"><CurrencyInput {...register("purchasePriceOverride")} /></Field><Field label="Selling override"><CurrencyInput {...register("sellingPriceOverride")} /></Field><Field label="Active"><Select {...register("isActive")}><option value="true">Active</option><option value="false">Inactive</option></Select></Field><Field label="Custom option name AR"><Input {...register("customOptionNameAr")} /></Field><Field label="Custom option name EN"><Input {...register("customOptionNameEn")} /></Field><Field label="Custom option value AR"><Input {...register("customOptionValueAr")} /></Field><Field label="Custom option value EN"><Input {...register("customOptionValueEn")} /></Field></div><Button disabled={save.isPending} type="submit">Save variant</Button></form>{selected ? <StockAdjust variant={product.variants.find((v) => v.id === selected)} onDone={() => queryClient.invalidateQueries({ queryKey: ["products", product.id] })} /> : null}<h2>Inventory movement history</h2>{movements.error ? <ErrorState error={movements.error} /> : <DataTable caption="Inventory movements" rows={movements.data ?? []} loading={movements.isLoading} columns={[{ key: "movementType", header: "Type", render: (m) => <StatusBadge value={m.movementType} /> }, { key: "quantity", header: "Quantity", numeric: true }, { key: "reason", header: "Reason" }, { key: "createdAt", header: "Created", render: (m) => formatDate(m.createdAt) }]} empty="No movement history" />}</Card>;
}

function StockAdjust({ variant, onDone }: { variant?: Variant; onDone: () => void }) {
  const [qty, setQty] = useState(String(variant?.stockQuantity ?? 0));
  const [reason, setReason] = useState("");
  const mutation = useMutation({ mutationFn: () => variantsApi.stock(variant!.id, Number(qty), reason), onSuccess: onDone });
  if (!variant) return null;
  return <Card className="grid"><h2>Adjust stock for {variant.sku}</h2><Field label="New stock quantity"><NumberInput value={qty} onChange={(e) => setQty(e.currentTarget.value)} /></Field><Field label="Reason"><Input value={reason} required onChange={(e) => setReason(e.currentTarget.value)} /></Field><Button disabled={!reason || mutation.isPending} onClick={() => mutation.mutate()}>Apply stock adjustment</Button>{mutation.error ? <ErrorState error={mutation.error} /> : null}</Card>;
}

export function CategoriesPage() { return <CrudList<Category> title="Categories" queryKey={["categories"]} list={categoriesApi.list} create={(d) => categoriesApi.create(castForm(d))} update={(id, d) => categoriesApi.update(id, castForm(d))} remove={categoriesApi.remove} fields={categoryFields} imageEntityType="categories" statusApi={categoriesApi.status} reorderApi={categoriesApi.reorder} columns={[{ key: "image", header: "Image", render: (r) => r.imageUrl ? <img className="image-thumb" src={r.imageUrl} alt={r.imageAltEn ?? ""} /> : "-" }, { key: "nameEn", header: "English name" }, { key: "nameAr", header: "Arabic name" }, { key: "sortOrder", header: "Sort", numeric: true }, { key: "productCount", header: "Products", numeric: true }, { key: "isActive", header: "Active", render: (r) => <StatusBadge value={r.isActive} /> }]} />; }

// Business fields only. Slugs are system-generated; SEO/AEO/GEO is automatic. descriptionAr/En are
// visible customer-facing category descriptions (rendered as textareas by CrudList).
const categoryFields = ["nameAr", "nameEn", "descriptionAr", "descriptionEn", "imageAltAr", "imageAltEn", "sortOrder", "isActive"];
const heroFields = ["titleAr", "titleEn", "subtitleAr", "subtitleEn", "ctaTextAr", "ctaTextEn", "ctaLink", "linkedProductId", "sortOrder", "isActive"];
const shippingFields = ["nameAr", "nameEn", "customerPaidShippingFee", "actualShippingCost", "sortOrder", "isActive"];
const expenseFields = ["category", "amount", "expenseDate", "notes", "relatedOrderId", "relatedCampaignName"];

function CrudList<T extends Record<string, any>>({ title, queryKey, list, create, update, remove, fields, columns, warning, imageEntityType, statusApi, reorderApi }: { title: string; queryKey: unknown[]; list: () => Promise<T[]>; create: (data: any) => Promise<T>; update: (id: string, data: any) => Promise<T>; remove?: (id: string) => Promise<any>; fields: string[]; columns: Column<T>[]; warning?: string; imageEntityType?: string; statusApi?: (id: string, isActive: boolean) => Promise<any>; reorderApi?: (items: { id: string; sortOrder: number }[]) => Promise<any> }) {
  const queryClient = useQueryClient();
  const [editing, setEditing] = useState<T | null>(null);
  const [uploadError, setUploadError] = useState<string | null>(null);
  const query = useQuery({ queryKey, queryFn: list });
  const { register, handleSubmit, reset, setValue, control } = useForm<any>();
  const save = useMutation({ mutationFn: (d: any) => editing ? update(editing.id, castForm(d)) : create(castForm(d)), onSuccess: async () => { setEditing(null); reset({}); await queryClient.invalidateQueries({ queryKey }); } });
  const del = useMutation({ mutationFn: (id: string) => remove!(id), onSuccess: () => queryClient.invalidateQueries({ queryKey }) });
  const status = useMutation({ mutationFn: ({ id, isActive }: { id: string; isActive: boolean }) => statusApi!(id, isActive), onSuccess: () => queryClient.invalidateQueries({ queryKey }) });
  const reorder = useMutation({ mutationFn: (items: { id: string; sortOrder: number }[]) => reorderApi!(items), onSuccess: () => queryClient.invalidateQueries({ queryKey }) });
  const upload = useMutation({ mutationFn: (file: File) => uploadsApi.image(file, imageEntityType, editing?.id), onSuccess: (uploaded) => { setUploadError(null); setValue("imageUrl", uploaded.url); setValue("imagePublicId", uploaded.publicId); }, onError: (e) => setUploadError(e instanceof Error ? e.message : "Upload failed.") });
  const watchedImage = useWatch({ control, name: "imageUrl" });
  const currentImage = imageEntityType ? watchedImage : undefined;
  const move = (rows: T[], index: number, dir: -1 | 1) => { const next = [...rows]; const target = index + dir; if (target < 0 || target >= next.length) return; [next[index], next[target]] = [next[target]!, next[index]!]; reorder.mutate(next.map((r, i) => ({ id: r.id, sortOrder: i + 1 }))); };
  const rows = query.data ?? [];
  const actionColumn: Column<T> = { key: "actions", header: "Actions", render: (row) => { const index = rows.findIndex((r) => r.id === row.id); return <div className="toolbar">{reorderApi ? <><Button variant="ghost" disabled={index <= 0 || reorder.isPending} onClick={() => move(rows, index, -1)} aria-label="Move up">↑</Button><Button variant="ghost" disabled={index >= rows.length - 1 || reorder.isPending} onClick={() => move(rows, index, 1)} aria-label="Move down">↓</Button></> : null}{statusApi ? <Button variant="secondary" onClick={() => status.mutate({ id: row.id, isActive: !row.isActive })}>{row.isActive ? "Deactivate" : "Activate"}</Button> : null}<Button variant="secondary" onClick={() => { setEditing(row); reset(row); }}>Edit</Button>{remove ? <ConfirmDialog title={`Delete ${title}`} body="This action is permanent when the backend permits deletion." destructive onConfirm={() => del.mutate(row.id)}>{(open) => <Button variant="danger" onClick={open}>Delete</Button>}</ConfirmDialog> : null}</div>; } };
  return <><PageHeader title={title} /><div className="grid grid-2"><Card>{warning ? <p className="empty">{warning}</p> : null}{query.error ? <ErrorState error={query.error} /> : <DataTable caption={title} rows={rows} loading={query.isLoading} columns={[...columns, actionColumn]} empty={`No ${title.toLowerCase()}`} />}</Card><Card><h2>{editing ? `Edit ${title}` : `Create ${title}`}</h2><form className="grid" onSubmit={handleSubmit((d) => save.mutate(d))}>{imageEntityType ? <Field label="Image" hint="Uploads to Cloudinary via apps/api. Secrets stay server-side. Save to apply.">{currentImage ? <img className="image-thumb" src={currentImage} alt="Current image preview" /> : <p className="empty">No image yet.</p>}<input type="hidden" {...register("imageUrl")} /><input type="hidden" {...register("imagePublicId")} /><Input type="file" accept="image/*" onChange={(e) => { const file = e.currentTarget.files?.[0]; if (file) upload.mutate(file); }} />{upload.isPending ? <p>Uploading…</p> : null}{uploadError ? <ErrorState error={new Error(uploadError)} /> : null}</Field> : null}{fields.map((field) => <Field key={field} label={label(field)}>{field === "isActive" || boolKeys.has(field) ? <Select {...register(field)}><option value="true">Yes</option><option value="false">No</option></Select> : /content|description/i.test(field) || field === "notes" ? <Textarea {...register(field)} /> : field === "expenseDate" ? <DateInput {...register(field)} /> : moneyKeys.has(field) ? <CurrencyInput {...register(field)} /> : field === "category" ? <Select {...register(field)}>{expenseCategories.map((x) => <option key={x} value={x}>{x}</option>)}</Select> : <Input {...register(field)} />}</Field>)}<Button disabled={save.isPending} type="submit">Save</Button>{editing ? <Button variant="secondary" type="button" onClick={() => { setEditing(null); reset({}); }}>Cancel edit</Button> : null}</form></Card></div></>;
}

function label(field: string) { return field.replace(/([A-Z])/g, " $1").replace(/^./, (c) => c.toUpperCase()); }

export function OrdersPage() {
  const { searchParams, page, pageSize, setParam, setPage } = usePagedParams();
  const query = { page, pageSize, status: searchParams.get("status") ?? undefined, search: searchParams.get("search") ?? undefined, from: searchParams.get("from") ?? undefined, to: searchParams.get("to") ?? undefined, paymentMethod: searchParams.get("paymentMethod") ?? undefined, governorate: searchParams.get("governorate") ?? undefined };
  const orders = useQuery({ queryKey: ["orders", query], queryFn: () => ordersApi.list(query) });
  return <><PageHeader title="Orders" /><Card className="filters"><Field label="Search"><Input defaultValue={query.search ?? ""} onBlur={(e) => setParam("search", e.currentTarget.value)} /></Field><Field label="Status"><Select defaultValue={query.status ?? ""} onChange={(e) => setParam("status", e.currentTarget.value)}><option value="">All</option>{orderStatuses.map((x) => <option key={x}>{x}</option>)}</Select></Field><Field label="Payment method"><Select defaultValue={query.paymentMethod ?? ""} onChange={(e) => setParam("paymentMethod", e.currentTarget.value)}><option value="">All</option>{paymentMethods.map((x) => <option key={x}>{x}</option>)}</Select></Field><Field label="From"><Input type="date" defaultValue={query.from ?? ""} onBlur={(e) => setParam("from", e.currentTarget.value)} /></Field><Field label="To"><Input type="date" defaultValue={query.to ?? ""} onBlur={(e) => setParam("to", e.currentTarget.value)} /></Field></Card>{orders.error ? <ErrorState error={orders.error} /> : <><DataTable caption="Orders" rows={orders.data?.items ?? []} loading={orders.isLoading} columns={orderListColumns} empty="No orders" /><Pagination page={orders.data?.page ?? page} totalPages={orders.data?.totalPages ?? 1} onPage={setPage} /></>}</>;
}

export function OrderDetailPage() {
  const { id } = useParams();
  const queryClient = useQueryClient();
  const order = useQuery({ queryKey: ["orders", id], queryFn: () => ordersApi.get(id!) });
  const status = useMutation({ mutationFn: (next: string) => ordersApi.status(id!, next), onSuccess: () => queryClient.invalidateQueries({ queryKey: ["orders", id] }) });
  const cancel = useMutation({ mutationFn: (reason: string) => ordersApi.cancel(id!, reason), onSuccess: () => queryClient.invalidateQueries({ queryKey: ["orders", id] }) });
  const ship = useMutation({ mutationFn: (data: any) => ordersApi.shipping(id!, data), onSuccess: () => queryClient.invalidateQueries({ queryKey: ["orders", id] }) });
  const { register, handleSubmit, reset } = useForm<any>();
  useEffect(() => { if (order.data) reset(order.data); }, [order.data, reset]);
  if (order.isLoading) return <Skeleton lines={8} />;
  if (order.error) return <ErrorState error={order.error} />;
  const o = order.data!;
  const nextStatus = nextOrderStatus(o.status);
  return <><PageHeader title={`Order ${o.orderNumber}`} actions={<LinkButton to="/orders">Back to orders</LinkButton>} /><div className="grid grid-3"><KpiCard label="Grand total" value={egp.format(o.grandTotal)} /><KpiCard label="Actual shipping cost" value={egp.format(o.actualShippingCost)} /><KpiCard label="Shipping margin" value={egp.format(o.shippingMargin)} /></div><div className="grid grid-2" style={{ marginTop: "1rem" }}><Card><h2>Status actions</h2><p>Backend controls allowed transitions and stock impact. Confirming deducts stock; eligible cancellation restores stock.</p><StatusBadge value={o.status} /> <StatusBadge value={o.paymentStatus} /><div className="toolbar" style={{ marginTop: "1rem" }}>{nextStatus ? <ConfirmDialog title={`Move to ${nextStatus}`} body="This calls the backend transition once. It will not be retried automatically." onConfirm={() => status.mutate(nextStatus)}>{(open) => <Button onClick={open}>{nextStatus === "Confirmed" ? "Confirm order" : `Mark ${nextStatus}`}</Button>}</ConfirmDialog> : null}{!/[Delivered|Cancelled]/.test(o.status) ? <ConfirmDialog title="Cancel order" body="Cancellation may restore deducted stock according to backend rules." destructive onConfirm={() => cancel.mutate("Cancelled by admin")}>{(open) => <Button variant="danger" onClick={open}>Cancel order</Button>}</ConfirmDialog> : null}</div>{status.error ? <ErrorState error={status.error} /> : null}{cancel.error ? <ErrorState error={cancel.error} /> : null}</Card><Card><h2>Shipping</h2><form className="grid" onSubmit={handleSubmit((d) => ship.mutate({ shippingProviderName: d.shippingProviderName, externalTrackingNumber: d.externalTrackingNumber, externalShippingStatus: d.externalShippingStatus }))}><Field label="Provider"><Input {...register("shippingProviderName")} /></Field><Field label="Tracking number"><Input {...register("externalTrackingNumber")} /></Field><Field label="External status"><Input {...register("externalShippingStatus")} /></Field><Button type="submit">Save shipping</Button></form></Card><Card><h2>Customer and address</h2><p>{o.customerName} ({o.customerPhone})</p><p>{o.governorateNameEn}, {o.cityDistrict}</p><p>{o.detailedAddress}</p><p>{safeText(o.notes)}</p></Card><Card><h2>Timeline</h2><JsonViewer data={{ createdAt: o.createdAt, confirmedAt: o.confirmedAt, preparingAt: o.preparingAt, shippedAt: o.shippedAt, deliveredAt: o.deliveredAt, cancelledAt: o.cancelledAt, cancellationReason: o.cancellationReason }} /></Card></div><Card style={{ marginTop: "1rem" } as any}><h2>Items</h2><DataTable caption="Order items" rows={o.items} columns={[{ key: "productNameEn", header: "Product" }, { key: "sku", header: "SKU" }, { key: "quantity", header: "Qty", numeric: true }, { key: "finalUnitPrice", header: "Final unit", numeric: true, render: (i) => egp.format(i.finalUnitPrice) }, { key: "purchaseCostPerUnit", header: "Purchase cost", numeric: true, render: (i) => egp.format(i.purchaseCostPerUnit) }, { key: "lineGrossProfit", header: "Gross profit", numeric: true, render: (i) => egp.format(i.lineGrossProfit) }]} /></Card></>;
}

function nextOrderStatus(status: string) { return status === "Pending" ? "Confirmed" : status === "Confirmed" ? "Preparing" : status === "Preparing" ? "Shipped" : status === "Shipped" ? "Delivered" : null; }

export function CustomersPage() {
  const { searchParams, page, pageSize, setParam, setPage } = usePagedParams();
  const customers = useQuery({ queryKey: ["customers", page, pageSize, searchParams.get("search")], queryFn: () => customersApi.list({ page, pageSize, search: searchParams.get("search") ?? undefined }) });
  return <><PageHeader title="Customers" /><Card className="filters"><Field label="Search"><Input defaultValue={searchParams.get("search") ?? ""} onBlur={(e) => setParam("search", e.currentTarget.value)} /></Field></Card>{customers.error ? <ErrorState error={customers.error} /> : <><DataTable caption="Customers" rows={customers.data?.items ?? []} loading={customers.isLoading} columns={[{ key: "fullName", header: "Name", render: (c) => <Link to={`/customers/${c.id}`}>{c.fullName}</Link> }, { key: "phoneNumber", header: "Phone" }, { key: "isPhoneVerified", header: "Verified", render: (c) => <StatusBadge value={c.isPhoneVerified} /> }, { key: "isActive", header: "Active", render: (c) => <StatusBadge value={c.isActive} /> }, { key: "totalOrders", header: "Orders", numeric: true }, { key: "deliveredOrders", header: "Delivered", numeric: true }, { key: "lastVisitAt", header: "Last visit", render: (c) => formatDate(c.lastVisitAt) }, { key: "lastOrderAt", header: "Last order", render: (c) => formatDate(c.lastOrderAt) }]} empty="No customers" /><Pagination page={customers.data?.page ?? page} totalPages={customers.data?.totalPages ?? 1} onPage={setPage} /></>}</>;
}

