const couponColumns: Column<Coupon>[] = [{ key: "code", header: "Code", render: (c) => <Link to={`/discounts/${c.id}`}>{c.code}</Link> }, { key: "type", header: "Type" }, { key: "value", header: "Value", numeric: true }, { key: "source", header: "Source" }, { key: "timesUsed", header: "Used", numeric: true }, { key: "isActive", header: "Active", render: (c) => <StatusBadge value={c.isActive} /> }];
export function TwoOrderSettingsPage() { const settings = useQuery({ queryKey: ["coupons", "two-order"], queryFn: couponsApi.twoOrder }); const { register, handleSubmit, reset } = useForm<any>(); useEffect(() => { if (settings.data) reset(settings.data); }, [settings.data, reset]); const save = useToastMutation((d: any) => couponsApi.updateTwoOrder(castForm(d) as any), ["coupons", "two-order"]); return <><PageHeader title="Two-delivered-orders settings" /><InlineMessage message={save.message} onClose={() => save.setMessage(null)} />{settings.error ? <ErrorState error={settings.error} /> : <Card><form className="grid" onSubmit={handleSubmit((d) => save.mutation.mutate(d))}><Field label="Enabled"><Select {...register("isEnabled")}><option value="true">Enabled</option><option value="false">Disabled</option></Select></Field><Field label="Discount percentage"><PercentageInput {...register("discountPercentage")} /></Field><Field label="Validity days"><NumberInput {...register("validityDays")} /></Field><Field label="Minimum subtotal"><CurrencyInput {...register("minimumOrderSubtotal")} /></Field><Field label="Send WhatsApp message"><Select {...register("sendWhatsAppMessage")}><option value="true">Yes</option><option value="false">No</option></Select></Field><Button type="submit">Save settings</Button></form></Card>}</>; }

export function ShippingPage() { return <CrudList<Governorate> title="Shipping governorates" queryKey={["shipping"]} list={shippingApi.list} create={(d) => shippingApi.create(castForm(d))} update={(id, d) => shippingApi.update(id, castForm(d))} fields={shippingFields} warning="Actual shipping cost is admin-internal. Historical order snapshots are not changed by editing current governorate fees." columns={[{ key: "nameEn", header: "Governorate" }, { key: "customerPaidShippingFee", header: "Customer-paid fee", numeric: true, render: (g) => egp.format(g.customerPaidShippingFee) }, { key: "actualShippingCost", header: "Actual cost", numeric: true, render: (g) => egp.format(g.actualShippingCost) }, { key: "margin", header: "Margin preview", numeric: true, render: (g) => egp.format(g.customerPaidShippingFee - g.actualShippingCost) }, { key: "isActive", header: "Active", render: (g) => <StatusBadge value={g.isActive} /> }]} />; }
export function HeroesPage() { return <CrudList<Hero> title="Heroes" queryKey={["heroes"]} list={heroesApi.list} create={(d) => heroesApi.create(castForm(d))} update={(id, d) => heroesApi.update(id, castForm(d))} remove={heroesApi.remove} fields={heroFields} imageEntityType="heroes" statusApi={heroesApi.status} reorderApi={heroesApi.reorder} columns={[{ key: "imageUrl", header: "Preview", render: (h) => h.imageUrl ? <img className="image-thumb" src={h.imageUrl} alt="" /> : "-" }, { key: "titleEn", header: "Title" }, { key: "ctaLink", header: "CTA link" }, { key: "sortOrder", header: "Sort", numeric: true }, { key: "isActive", header: "Active", render: (h) => <StatusBadge value={h.isActive} /> }]} />; }

export function WhatsAppLogsPage() {
  const { searchParams, page, pageSize, setParam, setPage } = usePagedParams(); const logs = useQuery({ queryKey: ["whatsapp", "messages", page, pageSize, searchParams.toString()], queryFn: () => whatsappApi.messages({ page, pageSize, status: searchParams.get("status") ?? undefined, type: searchParams.get("type") ?? undefined }) }); const retry = useToastMutation((id: string) => whatsappApi.retry(id), ["whatsapp", "messages"]); const test = useToastMutation((data: any) => whatsappApi.test(data), ["whatsapp", "messages"]); const { register, handleSubmit } = useForm<any>();
  return <><PageHeader title="WhatsApp logs" /><InlineMessage message={retry.message ?? test.message} onClose={() => { retry.setMessage(null); test.setMessage(null); }} /><Card className="filters"><Field label="Status"><Select defaultValue={searchParams.get("status") ?? ""} onChange={(e) => setParam("status", e.currentTarget.value)}><option value="">All</option><option>Pending</option><option>Sent</option><option>Failed</option></Select></Field><Field label="Type"><Select defaultValue={searchParams.get("type") ?? ""} onChange={(e) => setParam("type", e.currentTarget.value)}><option value="">All</option><option>Otp</option><option>OrderConfirmation</option><option>TwoOrderCoupon</option><option>AbandonedCheckout</option><option>InactiveCustomer</option><option>AdminTest</option></Select></Field></Card><div className="grid grid-2"><Card><h2>Send test message</h2><form className="grid" onSubmit={handleSubmit((d) => test.mutation.mutate(d))}><Field label="Phone"><Input {...register("phone")} /></Field><Field label="Message"><Input {...register("message")} /></Field><Button type="submit">Send test</Button></form></Card><Card><h2>Safe log details</h2><p>OTP bodies are redacted in the UI to avoid exposing one-time codes.</p></Card></div>{logs.error ? <ErrorState error={logs.error} /> : <><DataTable caption="WhatsApp messages" rows={logs.data?.items ?? []} loading={logs.isLoading} columns={[{ key: "phoneNumber", header: "Phone" }, { key: "messageType", header: "Type" }, { key: "status", header: "Status", render: (m) => <StatusBadge value={m.status} /> }, { key: "failureReason", header: "Failure" }, { key: "retryCount", header: "Retries", numeric: true }, { key: "sentAt", header: "Sent", render: (m) => formatDate(m.sentAt) }, { key: "messageBody", header: "Body/details", render: (m) => m.messageType === "Otp" ? "Redacted OTP message" : safeText(m.messageBody) }, { key: "actions", header: "Actions", render: (m) => m.status === "Failed" ? <Button variant="secondary" onClick={() => retry.mutation.mutate(m.id)}>Retry</Button> : "-" }]} empty="No WhatsApp messages" /><Pagination page={logs.data?.page ?? page} totalPages={logs.data?.totalPages ?? 1} onPage={setPage} /></>}</>;
}

export function ExpensesPage() { return <CrudList<Expense> title="Expenses" queryKey={["expenses"]} list={() => expensesApi.list({})} create={(d) => expensesApi.create(castForm(d))} update={(id, d) => expensesApi.update(id, castForm(d))} remove={expensesApi.remove} fields={expenseFields} warning="Payment gateway commissions may already come from PaymentTransactions. Shipping actual cost is not entered here for the same order." columns={[{ key: "category", header: "Category" }, { key: "amount", header: "Amount", numeric: true, render: (e) => egp.format(e.amount) }, { key: "expenseDate", header: "Date", render: (e) => formatDate(e.expenseDate) }, { key: "relatedCampaignName", header: "Campaign" }]} />; }

function useReportQuery() { const [range, setRange] = useState<ReportQuery["range"]>("ThisMonth"); const [from, setFrom] = useState(""); const [to, setTo] = useState(""); return { query: { range, from: range === "Custom" ? from : undefined, to: range === "Custom" ? to : undefined }, controls: <Card className="filters"><Field label="Range"><Select value={range} onChange={(e) => setRange(e.currentTarget.value as any)}>{reportRanges.map((x) => <option key={x}>{x}</option>)}</Select></Field><Field label="From"><Input type="date" value={from} onChange={(e) => setFrom(e.currentTarget.value)} disabled={range !== "Custom"} /></Field><Field label="To"><Input type="date" value={to} onChange={(e) => setTo(e.currentTarget.value)} disabled={range !== "Custom"} /></Field></Card> }; }
function reportRows(tab: string, query: ReportQuery) { if (tab === "Products") return reportsApi.products(query); if (tab === "Categories") return reportsApi.categories(query); if (tab === "Coupons") return reportsApi.coupons(query); if (tab === "Payments") return reportsApi.payments(query); if (tab === "Governorates") return reportsApi.governorates(query); if (tab === "Expenses") return reportsApi.expenses(query) as any; return reportsApi.analytics(query) as any; }
function reportColumns(rows: any[]): Column<any>[] { const sample = rows[0] ?? {}; return Object.keys(sample).map((key) => ({ key, header: label(key), numeric: typeof sample[key] === "number", render: (r) => typeof r[key] === "number" && /revenue|profit|cost|shipping|discount|commission|amount|expense/i.test(key) ? egp.format(r[key]) : safeText(r[key]) })); }
function ReportObject({ data, loading, error, moneyKeys }: { data?: Record<string, any>; loading: boolean; error: unknown; moneyKeys: string[] }) { if (loading) return <Skeleton lines={8} />; if (error) return <ErrorState error={error} />; const rows = Object.entries(data ?? {}).map(([metric, value]) => ({ metric: label(metric), value: moneyKeys.includes(metric) && typeof value === "number" ? egp.format(value) : typeof value === "number" && /conversion/i.test(metric) ? percent.format(value) : safeText(value) })); return <DataTable caption="Report summary" rows={rows} columns={[{ key: "metric", header: "Metric" }, { key: "value", header: "Backend value" }]} />; }

function AnalyticsView({ data }: { data: AnalyticsReport }) { const bars = [{ label: "Sessions", value: data.sessions }, { label: "Unique visitors", value: data.uniqueVisitors }, { label: "Checkout started", value: data.checkoutStartedSessions }, { label: "Orders", value: data.orderPlacedSessions }, { label: "Delivered visitors", value: data.deliveredVisitors }]; return <div className="grid grid-2"><Card><h2>First-party funnel</h2><ChartBars rows={bars} /></Card><Card><h2>Conversions</h2><DataTable caption="Conversion rates" rows={[{ metric: "Visit to order", value: percent.format(data.visitToOrderConversion) }, { metric: "Checkout to order", value: percent.format(data.checkoutToOrderConversion) }, { metric: "Order to delivered", value: percent.format(data.orderToDeliveredConversion) }]} columns={[{ key: "metric", header: "Metric" }, { key: "value", header: "Backend value" }]} /></Card><Card><h2>Breakdowns</h2><p>Traffic, device, UTM, referrer and language breakdowns render when exposed by the backend analytics contract.</p><JsonViewer data={{ trafficSources: data.trafficSources ?? [], deviceTypes: data.deviceTypes ?? [], languages: data.languages ?? [] }} /></Card></div>; }



export function CanonicalDashboardPage() {
  const summary = useQuery({ queryKey: ["dashboard", "summary"], queryFn: dashboardApi.summary });
  const recent = useQuery({ queryKey: ["dashboard", "recent"], queryFn: () => dashboardApi.recentOrders(8) });
  const alerts = useQuery({ queryKey: ["dashboard", "alerts"], queryFn: dashboardApi.alerts });
  const payments = useQuery({ queryKey: ["payments", "readiness"], queryFn: paymentsApi.readiness });
  const whatsapp = useQuery({ queryKey: ["whatsapp", "status"], queryFn: whatsappApi.status });
  if (summary.isLoading) return <Skeleton lines={8} />;
  if (summary.error) return <ErrorState error={summary.error} />;
  const s = summary.data;
  const paymentReady = payments.data?.filter((p) => p.readinessStatus === "Ready").length ?? 0;
  return <><PageHeader title="Dashboard" eyebrow="Authenticated admin overview" /><div className="grid grid-4"><KpiCard label="Today orders" value={integer.format(s?.todayOrders ?? 0)} to="/orders" /><KpiCard label="Today revenue" value={egp.format(s?.todayRevenue ?? 0)} to="/reports" /><KpiCard label="Delivered this month" value={integer.format(s?.deliveredOrdersThisMonth ?? 0)} to="/orders" /><KpiCard label="Pending orders" value={integer.format(s?.pendingOrders ?? 0)} to="/orders?status=Pending" /><KpiCard label="Low-stock variants" value={integer.format(s?.lowStockVariants ?? 0)} to="/products" /><KpiCard label="Failed WhatsApp" value={integer.format(s?.failedWhatsAppMessages ?? 0)} to="/whatsapp" /><KpiCard label="Conversion rate" value={percent.format(s?.conversionRateThisMonth ?? 0)} to="/reports" /><KpiCard label="Net profit this month" value={egp.format(s?.netProfitThisMonth ?? 0)} to="/reports" /></div><div className="grid grid-4" style={{ marginTop: "1rem" }}><Card><h2>Payment readiness</h2><p>{paymentReady} configured payment method(s).</p>{payments.error ? <ErrorState error={payments.error} /> : null}</Card><Card><h2>WhatsApp connection</h2><StatusBadge value={whatsapp.data?.connected ? "connected" : "disconnected"} /><p>{safeText(whatsapp.data?.state ?? whatsapp.data?.detail)}</p></Card><Card><h2>Failed WhatsApp</h2><p>{integer.format(s?.failedWhatsAppMessages ?? 0)} failed message(s).</p><LinkButton to="/whatsapp">Open WhatsApp</LinkButton></Card></div><div className="grid grid-2" style={{ marginTop: "1rem" }}><Card><h2>Recent orders</h2>{recent.error ? <ErrorState error={recent.error} /> : <DataTable caption="Recent orders" rows={recent.data ?? []} loading={recent.isLoading} columns={orderListColumns} empty="No recent orders" />}</Card><Card><h2>Alerts</h2>{alerts.error ? <ErrorState error={alerts.error} /> : !alerts.data?.length ? <EmptyState title="No active alerts" body="Operational alerts will appear when the backend reports them." /> : <DataTable caption="Dashboard alerts" rows={alerts.data} columns={[{ key: "type", header: "Type", render: (r) => <StatusBadge value={r.type} /> }, { key: "message", header: "Message" }, { key: "count", header: "Count", numeric: true }]} />}</Card></div></>;
}

export function DiscountsPage() {
  const [tab, setTab] = useState("Coupons");
  const coupons = useQuery({ queryKey: ["coupons"], queryFn: couponsApi.list });
  return <><PageHeader title="Discounts" actions={tab === "Coupons" ? <LinkButton to="/discounts/new" variant="primary">New coupon</LinkButton> : undefined} /><Tabs tabs={["Coupons", "Two-delivered-orders reward"]} active={tab} onChange={setTab} />{tab === "Coupons" ? coupons.error ? <ErrorState error={coupons.error} /> : <DataTable caption="Coupons" rows={coupons.data ?? []} loading={coupons.isLoading} columns={[{ key: "code", header: "Code", render: (c) => <Link to={`/discounts/${c.id}`}>{c.code}</Link> }, { key: "type", header: "Type" }, { key: "value", header: "Value", numeric: true }, { key: "source", header: "Source" }, { key: "timesUsed", header: "Used", numeric: true }, { key: "isActive", header: "Active", render: (c) => <StatusBadge value={c.isActive} /> }]} empty="No coupons" /> : <TwoOrderSettingsPage />}</>;
}

export function CanonicalCouponDetailPage({ mode }: { mode?: "new" }) {
  const { id } = useParams();
  const isNew = mode === "new" || !id;
  const navigate = useNavigate();
  const coupon = useQuery({ queryKey: ["coupons", id], queryFn: () => couponsApi.get(id!), enabled: !isNew });
  const usage = useQuery({ queryKey: ["coupons", id, "usage"], queryFn: () => couponsApi.usage(id!), enabled: !isNew });
  const { register, handleSubmit, reset } = useForm<any>({ defaultValues: { type: "Percentage", isActive: true, isCustomerSpecific: false } });
  useEffect(() => { if (coupon.data) reset(coupon.data); }, [coupon.data, reset]);
  const save = useToastMutation((d: any) => isNew ? couponsApi.create(castForm(d)) : couponsApi.update(id!, castForm(d)), ["coupons"]);
  if (coupon.isLoading) return <Skeleton lines={8} />;
  if (coupon.error) return <ErrorState error={coupon.error} />;
  return <><PageHeader title={isNew ? "New coupon" : coupon.data?.code ?? "Coupon"} actions={<LinkButton to="/discounts">Back to discounts</LinkButton>} /><InlineMessage message={save.message} onClose={() => save.setMessage(null)} /><div className="grid grid-2"><Card><form className="grid" onSubmit={handleSubmit(async (d) => { const saved = await save.mutation.mutateAsync(d) as Coupon; if (isNew) navigate(`/discounts/${saved.id}`); })}><Field label="Code"><Input {...register("code")} /></Field><Field label="Type"><Select {...register("type")}>{couponTypes.map((x) => <option key={x}>{x}</option>)}</Select></Field><Field label="Value"><CurrencyInput {...register("value")} /></Field><Field label="Start"><DateInput {...register("startAt")} /></Field><Field label="End"><DateInput {...register("endAt")} /></Field><Field label="Total usage limit"><NumberInput {...register("totalUsageLimit")} /></Field><Field label="Per-customer usage limit"><NumberInput {...register("perCustomerUsageLimit")} /></Field><Field label="Minimum subtotal"><CurrencyInput {...register("minimumOrderSubtotal")} /></Field><Field label="Active"><Select {...register("isActive")}><option value="true">Active</option><option value="false">Inactive</option></Select></Field><Field label="Customer specific"><Select {...register("isCustomerSpecific")}><option value="false">General</option><option value="true">Customer-specific</option></Select></Field><Field label="Customer ID"><Input {...register("customerId")} /></Field><Button type="submit">Save coupon</Button></form></Card>{!isNew ? <Card><h2>Usage</h2><DataTable caption="Coupon usage" rows={usage.data ?? []} loading={usage.isLoading} columns={[{ key: "customerId", header: "Customer" }, { key: "orderId", header: "Order" }, { key: "discountAmount", header: "Discount", numeric: true, render: (u) => egp.format(u.discountAmount) }, { key: "usedAt", header: "Used", render: (u) => formatDate(u.usedAt) }]} empty="No usage" /></Card> : null}</div></>;
}

export function StorefrontContentPage() {
  const [tab, setTab] = useState("Heroes");
  const pages = useQuery({ queryKey: ["pages"], queryFn: pagesApi.list });
  return <><PageHeader title="Storefront Content" /><Tabs tabs={["Heroes", "Pages"]} active={tab} onChange={setTab} />{tab === "Heroes" ? <HeroesPage /> : pages.error ? <ErrorState error={pages.error} /> : <DataTable caption="Pages" rows={pages.data ?? []} loading={pages.isLoading} columns={[{ key: "titleEn", header: "Title", render: (p) => <Link to={`/content/pages/${p.id}`}>{p.titleEn}</Link> }, { key: "titleAr", header: "Arabic title" }, { key: "isActive", header: "Active", render: (p) => <StatusBadge value={p.isActive} /> }]} empty="No pages" />}</>;
}

export function CanonicalPageDetailPage() {
  const { id } = useParams();
  const page = useQuery({ queryKey: ["pages", id], queryFn: () => pagesApi.get(id!) });
  const { register, handleSubmit, reset } = useForm<any>();
  useEffect(() => { if (page.data) reset(page.data); }, [page.data, reset]);
  const save = useToastMutation((d: any) => pagesApi.update(id!, castForm(d)), ["pages"]);
  if (page.isLoading) return <Skeleton lines={8} />;
  if (page.error) return <ErrorState error={page.error} />;
  return <><PageHeader title={page.data?.titleEn ?? "Page"} actions={<LinkButton to="/content">Back to Storefront Content</LinkButton>} /><InlineMessage message={save.message} onClose={() => save.setMessage(null)} /><Card><form className="grid grid-2" onSubmit={handleSubmit((d) => save.mutation.mutate(d))}><Field label="Arabic title"><Input {...register("titleAr")} /></Field><Field label="English title"><Input {...register("titleEn")} /></Field><Field label="Arabic content"><Textarea {...register("contentAr")} /></Field><Field label="English content"><Textarea {...register("contentEn")} /></Field><Field label="Active"><Select {...register("isActive")}><option value="true">Active</option><option value="false">Inactive</option></Select></Field><p>Page routes and identifiers are generated automatically by the application from this title and content. Admins edit only the page title, content, and visibility.</p><Button type="submit">Save page</Button></form></Card></>;
}

export function CanonicalShippingPage() {
  const settings = useQuery({ queryKey: ["shipping", "settings"], queryFn: shippingApi.settings });
  const { register, handleSubmit, reset } = useForm<any>();
  useEffect(() => { if (settings.data) reset(settings.data); }, [settings.data, reset]);
  const save = useToastMutation((d: any) => shippingApi.updateSettings(castForm(d) as any), ["shipping", "settings"]);
  return <><PageHeader title="Shipping" /><InlineMessage message={save.message} onClose={() => save.setMessage(null)} /><div className="grid grid-2"><Card><h2>Free-shipping rule</h2>{settings.error ? <ErrorState error={settings.error} /> : <form className="grid" onSubmit={handleSubmit((d) => save.mutation.mutate(d))}><Field label="Free shipping enabled"><Select {...register("isFreeShippingEnabled")}><option value="true">Enabled</option><option value="false">Disabled</option></Select></Field><Field label="Threshold"><CurrencyInput {...register("freeShippingThreshold")} /></Field><Button type="submit">Save free-shipping rule</Button></form>}</Card><Card><h2>Governorates and fees</h2><p>Customer-paid fee, actual shipping cost, active status, sort order, and shipping margin remain owned here.</p></Card></div><div style={{ marginTop: "1rem" }}><ShippingPage /></div></>;
}

export function WhatsAppPage() {
  const [tab, setTab] = useState("Connection");
  const settings = useQuery({ queryKey: ["whatsapp", "settings"], queryFn: whatsappApi.settings });
  const status = useQuery({ queryKey: ["whatsapp", "status"], queryFn: whatsappApi.status });
  const qr = useQuery({ queryKey: ["whatsapp", "qr"], queryFn: whatsappApi.qr, enabled: tab === "Connection" });
  const health = useQuery({ queryKey: ["whatsapp", "health"], queryFn: whatsappApi.health, enabled: tab === "Connection" });
  const automations = useQuery({ queryKey: ["whatsapp", "automations"], queryFn: whatsappApi.automations });
  const { register: registerSettings, handleSubmit: submitSettings, reset: resetSettings } = useForm<any>();
  const { register: registerAutomations, handleSubmit: submitAutomations, reset: resetAutomations } = useForm<any>();
  useEffect(() => { if (settings.data) resetSettings(settings.data); }, [settings.data, resetSettings]);
  useEffect(() => { if (automations.data) resetAutomations(automations.data); }, [automations.data, resetAutomations]);
  const saveSettings = useToastMutation((d: any) => whatsappApi.updateSettings(castForm(d)), ["whatsapp", "settings"]);
  const saveAutomations = useToastMutation((d: any) => whatsappApi.updateAutomations(castForm(d) as any), ["whatsapp", "automations"]);
  const logout = useToastMutation(() => whatsappApi.logout(), ["whatsapp", "status"]);
  const resetSession = useToastMutation(() => whatsappApi.resetSession(), ["whatsapp", "status"]);
  return <><PageHeader title="WhatsApp" /><InlineMessage message={saveSettings.message ?? saveAutomations.message ?? logout.message ?? resetSession.message} onClose={() => { saveSettings.setMessage(null); saveAutomations.setMessage(null); logout.setMessage(null); resetSession.setMessage(null); }} /><Tabs tabs={["Connection", "Templates", "Automations", "Logs"]} active={tab} onChange={setTab} />{tab === "Connection" ? <div className="grid grid-2"><Card><h2>Connection</h2><StatusBadge value={status.data?.connected ? "connected" : "disconnected"} /><StatusBadge value={status.data?.reachable ? "reachable" : "unreachable"} /><SecretStatus label="Internal API key" configured={!!status.data?.keyConfigured} /><SecretStatus label="Service configuration" configured={!!settings.data?.serviceConfigured} /><p>{safeText(status.data?.detail ?? status.data?.state)}</p><div className="toolbar"><Button variant="secondary" onClick={() => void qr.refetch()}>Refresh QR</Button><Button variant="secondary" onClick={() => logout.mutation.mutate()}>Logout</Button><Button variant="danger" onClick={() => resetSession.mutation.mutate()}>Reset session</Button></div></Card><Card><h2>Pairing QR</h2>{qr.data?.qrDataUri ? <img className="image-thumb" src={qr.data.qrDataUri} alt="WhatsApp pairing QR" /> : <p className="empty">{safeText(qr.data?.error ?? status.data?.error ?? "No QR available yet.")}</p>}<h2>Health</h2><p>{health.data?.reachable ? "Sidecar reachable" : "Sidecar unreachable"}</p><p>{safeText(health.data?.detail ?? health.data?.error)}</p></Card></div> : tab === "Templates" ? <Card><form className="grid" onSubmit={submitSettings((d) => saveSettings.mutation.mutate(d))}><Field label="Enabled"><Select {...registerSettings("isEnabled")}><option value="true">Enabled</option><option value="false">Disabled</option></Select></Field><Field label="Transport"><Input value={settings.data?.transportName ?? "BaileysWhatsAppWeb"} readOnly /></Field><p>Registration OTP, password-reset OTP, phone-change OTP, and order confirmation templates are fixed in code and are not editable.</p><Field label="Two-delivered-orders reward template"><Textarea {...registerSettings("twoOrderCouponTemplate")} /></Field><Field label="Abandoned checkout template"><Textarea {...registerSettings("abandonedCheckoutTemplate")} /></Field><Field label="Inactive customer template"><Textarea {...registerSettings("inactiveCustomerTemplate")} /></Field><Button type="submit">Save templates</Button></form></Card> : tab === "Automations" ? <Card><form className="grid" onSubmit={submitAutomations((d) => saveAutomations.mutation.mutate(d))}><Field label="Abandoned checkout enabled"><Select {...registerAutomations("abandonedCheckoutEnabled")}><option value="true">Enabled</option><option value="false">Disabled</option></Select></Field><Field label="Abandoned checkout delay hours"><NumberInput {...registerAutomations("abandonedCheckoutDelayHours")} /></Field><Field label="Inactive customer enabled"><Select {...registerAutomations("inactiveCustomerEnabled")}><option value="true">Enabled</option><option value="false">Disabled</option></Select></Field><Field label="Inactive customer delay days"><NumberInput {...registerAutomations("inactiveCustomerDelayDays")} /></Field><p>Two-order discount percentage and validity are owned by Discounts. WhatsApp owns only notification templates and automation status.</p><Button type="submit">Save automations</Button></form></Card> : <WhatsAppLogsPage />}</>;
}

export function CanonicalCustomersPage() {
  const { searchParams, page, pageSize, setParam, setPage } = usePagedParams();
  const queryClient = useQueryClient();
  const customers = useQuery({ queryKey: ["customers", page, pageSize, searchParams.get("search")], queryFn: () => customersApi.list({ page, pageSize, search: searchParams.get("search") ?? undefined }) });
  const status = useMutation({ mutationFn: ({ id, isActive }: { id: string; isActive: boolean }) => customersApi.status(id, isActive), onSuccess: async () => queryClient.invalidateQueries({ queryKey: ["customers"] }) });
  return <><PageHeader title="Customers" /><Card className="filters"><Field label="Search"><Input defaultValue={searchParams.get("search") ?? ""} onBlur={(e) => setParam("search", e.currentTarget.value)} /></Field></Card>{customers.error ? <ErrorState error={customers.error} /> : <><DataTable caption="Customers" rows={customers.data?.items ?? []} loading={customers.isLoading} columns={[{ key: "fullName", header: "Name", render: (c) => <Link to={`/customers/${c.id}`}>{c.fullName}</Link> }, { key: "phoneNumber", header: "Phone" }, { key: "isPhoneVerified", header: "Verified", render: (c) => <StatusBadge value={c.isPhoneVerified} /> }, { key: "isActive", header: "Active", render: (c) => <StatusBadge value={c.isActive} /> }, { key: "totalOrders", header: "Orders", numeric: true }, { key: "deliveredOrders", header: "Delivered", numeric: true }, { key: "lastVisitAt", header: "Last visit", render: (c) => formatDate(c.lastVisitAt) }, { key: "actions", header: "Actions", render: (c) => <ConfirmDialog title={c.isActive ? "Deactivate customer" : "Activate customer"} body="This changes whether the customer can sign in and place orders." destructive={c.isActive} onConfirm={() => status.mutate({ id: c.id, isActive: !c.isActive })}>{(open) => <Button variant={c.isActive ? "danger" : "secondary"} onClick={open}>{c.isActive ? "Deactivate" : "Activate"}</Button>}</ConfirmDialog> }]} empty="No customers" /><Pagination page={customers.data?.page ?? page} totalPages={customers.data?.totalPages ?? 1} onPage={setPage} /></>}</>;
}

export function CanonicalReportsPage() {
  const [tab, setTab] = useState("Sales");
  const { query, controls } = useReportQuery();
  const sales = useQuery({ queryKey: ["reports", "sales", query], queryFn: () => reportsApi.sales(query) });
  const profit = useQuery({ queryKey: ["reports", "profit", query], queryFn: () => reportsApi.profit(query) });
  const analytics = useQuery({ queryKey: ["reports", "analytics", query], queryFn: () => reportsApi.analytics(query), enabled: tab === "Analytics" });
  const rows = useQuery({ queryKey: ["reports", tab, query], queryFn: () => reportRows(tab, query), enabled: !["Sales", "Profit", "Analytics"].includes(tab) });
  const tabs = ["Sales", "Profit", "Products", "Categories", "Coupons", "Payments", "Governorates", "Expenses", "Analytics"];
  return <><PageHeader title="Reports" /><Tabs tabs={tabs} active={tab} onChange={setTab} />{controls}{tab === "Sales" ? <ReportObject data={sales.data} loading={sales.isLoading} error={sales.error} moneyKeys={["deliveredProductRevenue", "deliveredGrandTotal", "productDiscountTotal", "couponDiscountTotal"]} /> : tab === "Profit" ? <ReportObject data={profit.data} loading={profit.isLoading} error={profit.error} moneyKeys={["productRevenueAfterDiscounts", "productPurchaseCost", "grossProfit", "shippingCollected", "actualShippingCost", "shippingMargin", "expenses", "paymentCommissions", "netProfit"]} /> : tab === "Analytics" ? analytics.error ? <ErrorState error={analytics.error} /> : analytics.isLoading ? <Skeleton lines={8} /> : <AnalyticsView data={analytics.data!} /> : rows.error ? <ErrorState error={rows.error} /> : <DataTable caption={`${tab} report`} rows={(rows.data ?? []) as RowReport[]} loading={rows.isLoading} columns={reportColumns(rows.data ?? [])} empty="No report results for selected period" />}</>;
}

export function NotFoundPage() { return <><PageHeader title="Page not found" /><Card><p>The requested admin route does not exist.</p><LinkButton to="/dashboard">Go to dashboard</LinkButton></Card></>; }
